+
+    const anchors = extractSearchAnchors(diary);
+    const lowerAnchors = anchors.map(a => a.toLowerCase());
+
+    // Should find file patterns
+    expect(lowerAnchors.some(a => a.includes("package.json"))).toBe(true);
